/**
 * Breadcrumb — Navigation trail showing the user's location in a
 * hierarchical site.
 *
 * A pure-CSS component (the semantics of `<nav aria-label="breadcrumb">`
 * combined with `<ol>` are more appropriate than any library primitive).
 * Inline icons are used so this component can be copied into any project
 * without extra dependencies.
 *
 * Anatomy:
 * ```tsx
 * <Breadcrumb>
 *   <BreadcrumbList>
 *     <BreadcrumbItem>
 *       <BreadcrumbLink href="/">Home</BreadcrumbLink>
 *     </BreadcrumbItem>
 *     <BreadcrumbSeparator />
 *     <BreadcrumbItem>
 *       <BreadcrumbLink href="/docs">Docs</BreadcrumbLink>
 *     </BreadcrumbItem>
 *     <BreadcrumbSeparator />
 *     <BreadcrumbItem>
 *       <BreadcrumbPage>Breadcrumb</BreadcrumbPage>
 *     </BreadcrumbItem>
 *   </BreadcrumbList>
 * </Breadcrumb>
 * ```
 *
 * Accessibility: the root is `<nav aria-label="breadcrumb">`; the current
 * page uses `aria-current="page"` and `aria-disabled="true"`. Separators
 * are `aria-hidden`.
 *
 * @package    @edbn/ui
 * @version    0.3.0
 * @since      0.1.0
 * @brand      edbn/ui — https://ui.edbn.me
 * @docs       https://ui.edbn.me/docs/components/breadcrumb
 * @registryDescription Navigation breadcrumb trail with separator support.
 */

"use client";

import * as React from "react";

import { cn } from "@/lib/utils";
import { Slot } from "@/lib/slot";

// ---- ROOT -------------------------------------------------------------------

export type BreadcrumbProps = React.ComponentPropsWithoutRef<"nav"> & {
  /** Custom separator element. When omitted, a chevron-right is used. */
  separator?: React.ReactNode;
};

/**
 * The breadcrumb landmark.
 *
 * @since 0.1.0
 */
function Breadcrumb({ separator: _separator, ...props }: BreadcrumbProps) {
  // `separator` is reserved for future API — destructure to keep it off DOM.
  return <nav aria-label="breadcrumb" data-slot="breadcrumb" {...props} />;
}
Breadcrumb.displayName = "Breadcrumb";

// ---- LIST -------------------------------------------------------------------

export type BreadcrumbListProps = React.ComponentPropsWithoutRef<"ol">;

/**
 * Ordered list of breadcrumb items.
 *
 * @since 0.1.0
 */
function BreadcrumbList({ className, ...props }: BreadcrumbListProps) {
  return (
    <ol
      data-slot="breadcrumb-list"
      className={cn(
        "flex flex-wrap items-center gap-1.5 break-words text-sm text-muted-foreground sm:gap-2.5",
        className
      )}
      {...props}
    />
  );
}
BreadcrumbList.displayName = "BreadcrumbList";

// ---- ITEM -------------------------------------------------------------------

export type BreadcrumbItemProps = React.ComponentPropsWithoutRef<"li">;

/**
 * Individual breadcrumb cell. Wraps a `BreadcrumbLink` or
 * `BreadcrumbPage`.
 *
 * @since 0.1.0
 */
function BreadcrumbItem({ className, ...props }: BreadcrumbItemProps) {
  return (
    <li
      data-slot="breadcrumb-item"
      className={cn("inline-flex items-center gap-1.5", className)}
      {...props}
    />
  );
}
BreadcrumbItem.displayName = "BreadcrumbItem";

// ---- LINK -------------------------------------------------------------------

export type BreadcrumbLinkProps = React.ComponentPropsWithoutRef<"a"> & {
  /** When `true`, passes props to the child instead of rendering an `<a>`. */
  asChild?: boolean;
};

/**
 * A navigable breadcrumb. Supports `asChild` to compose with
 * framework-specific link components (e.g. `next/link`).
 *
 * @since 0.1.0
 */
function BreadcrumbLink({
  className,
  asChild,
  ...props
}: BreadcrumbLinkProps) {
  const Comp = asChild ? Slot : "a";
  return (
    <Comp
      data-slot="breadcrumb-link"
      className={cn(
        "transition-colors duration-150 ease-out motion-reduce:transition-none",
        "hover:text-foreground",
        "focus-visible:outline-none focus-visible:text-foreground focus-visible:underline underline-offset-4",
        className
      )}
      {...props}
    />
  );
}
BreadcrumbLink.displayName = "BreadcrumbLink";

// ---- PAGE -------------------------------------------------------------------

export type BreadcrumbPageProps = React.ComponentPropsWithoutRef<"span">;

/**
 * The current page's label. Non-interactive; `aria-current="page"`
 * identifies it to assistive tech.
 *
 * @since 0.1.0
 */
function BreadcrumbPage({ className, ...props }: BreadcrumbPageProps) {
  return (
    <span
      role="link"
      aria-disabled="true"
      aria-current="page"
      data-slot="breadcrumb-page"
      className={cn("font-normal text-foreground", className)}
      {...props}
    />
  );
}
BreadcrumbPage.displayName = "BreadcrumbPage";

// ---- SEPARATOR --------------------------------------------------------------

export type BreadcrumbSeparatorProps = React.ComponentPropsWithoutRef<"li">;

/**
 * Visual divider between items. Renders a chevron by default; pass
 * `children` to override.
 *
 * @since 0.1.0
 */
function BreadcrumbSeparator({
  children,
  className,
  ...props
}: BreadcrumbSeparatorProps) {
  return (
    <li
      role="presentation"
      aria-hidden="true"
      data-slot="breadcrumb-separator"
      className={cn("[&>svg]:size-3.5", className)}
      {...props}
    >
      {children ?? <ChevronRightIcon />}
    </li>
  );
}
BreadcrumbSeparator.displayName = "BreadcrumbSeparator";

// ---- ELLIPSIS ---------------------------------------------------------------

export type BreadcrumbEllipsisProps = React.ComponentPropsWithoutRef<"span">;

/**
 * Collapsed-items indicator. Useful when the trail is too long — render
 * this in place of middle items with a popover / menu of the hidden ones.
 *
 * @since 0.1.0
 */
function BreadcrumbEllipsis({
  className,
  ...props
}: BreadcrumbEllipsisProps) {
  return (
    <span
      role="presentation"
      aria-hidden="true"
      data-slot="breadcrumb-ellipsis"
      className={cn("flex h-9 w-9 items-center justify-center", className)}
      {...props}
    >
      <EllipsisIcon className="size-4" />
      <span className="sr-only">More</span>
    </span>
  );
}
BreadcrumbEllipsis.displayName = "BreadcrumbEllipsis";

// ---- INLINE ICONS -----------------------------------------------------------

function ChevronRightIcon(props: React.ComponentPropsWithoutRef<"svg">) {
  return (
    <svg
      xmlns="http://www.w3.org/2000/svg"
      width="16"
      height="16"
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth="2"
      strokeLinecap="round"
      strokeLinejoin="round"
      {...props}
    >
      <path d="m9 18 6-6-6-6" />
    </svg>
  );
}

function EllipsisIcon(props: React.ComponentPropsWithoutRef<"svg">) {
  return (
    <svg
      xmlns="http://www.w3.org/2000/svg"
      width="16"
      height="16"
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth="2"
      strokeLinecap="round"
      strokeLinejoin="round"
      {...props}
    >
      <circle cx="12" cy="12" r="1" />
      <circle cx="19" cy="12" r="1" />
      <circle cx="5" cy="12" r="1" />
    </svg>
  );
}

// ---- EXPORTS ----------------------------------------------------------------

export {
  Breadcrumb,
  BreadcrumbList,
  BreadcrumbItem,
  BreadcrumbLink,
  BreadcrumbPage,
  BreadcrumbSeparator,
  BreadcrumbEllipsis,
};

/**
 * Primitive Component Adapter Layer
 *
 * Re-exports headless UI primitives used by edbn-ui components.
 * Components import from this file instead of directly from provider packages.
 *
 * Base UI (@base-ui/react) is the primary primitive provider.
 * Slot is vendored locally (oss/lib/slot.ts).
 *
 * @packageDocumentation
 * @registryDescription Re-exports of headless UI primitives (Base UI, Slot) used across edbn-ui components.
 */

// ---- SLOT (Polymorphic rendering) -------------------------------------------

export { Slot } from "./slot";

// ---- AVATAR (Base UI) -------------------------------------------------------

export { Avatar as AvatarPrimitive } from "@base-ui/react/avatar";

// ---- BASE UI PRIMITIVES -----------------------------------------------------

export { Accordion as AccordionPrimitive } from "@base-ui/react/accordion";
export { AlertDialog as AlertDialogPrimitive } from "@base-ui/react/alert-dialog";
export { Checkbox as CheckboxPrimitive } from "@base-ui/react/checkbox";
export { CheckboxGroup as CheckboxGroupPrimitive } from "@base-ui/react/checkbox-group";
export { Collapsible as CollapsiblePrimitive } from "@base-ui/react/collapsible";
export { Dialog as DialogPrimitive } from "@base-ui/react/dialog";
export { Field as FieldPrimitive } from "@base-ui/react/field";
export { Fieldset as FieldsetPrimitive } from "@base-ui/react/fieldset";
export { Form as FormPrimitive } from "@base-ui/react/form";
export { Input as InputPrimitive } from "@base-ui/react/input";
export { Menu as MenuPrimitive } from "@base-ui/react/menu";
export { NumberField as NumberFieldPrimitive } from "@base-ui/react/number-field";
export { Popover as PopoverPrimitive } from "@base-ui/react/popover";
export { PreviewCard as PreviewCardPrimitive } from "@base-ui/react/preview-card";
export { Progress as ProgressPrimitive } from "@base-ui/react/progress";
export { Radio as RadioPrimitive } from "@base-ui/react/radio";
export { RadioGroup as RadioGroupPrimitive } from "@base-ui/react/radio-group";
export { ScrollArea as ScrollAreaPrimitive } from "@base-ui/react/scroll-area";
export { Select as SelectPrimitive } from "@base-ui/react/select";
export { Separator as SeparatorPrimitive } from "@base-ui/react/separator";
export { Slider as SliderPrimitive } from "@base-ui/react/slider";
export { Switch as SwitchPrimitive } from "@base-ui/react/switch";
export { Tabs as TabsPrimitive } from "@base-ui/react/tabs";
export { Toast as ToastPrimitive } from "@base-ui/react/toast";
export { Toggle as TogglePrimitive } from "@base-ui/react/toggle";
export { ToggleGroup as ToggleGroupPrimitive } from "@base-ui/react/toggle-group";
export { Toolbar as ToolbarPrimitive } from "@base-ui/react/toolbar";
export { Tooltip as TooltipPrimitive } from "@base-ui/react/tooltip";

/**
 * Slot Component - Polymorphic Rendering
 *
 * A vendored Slot implementation for the `asChild` prop pattern.
 * Merges props, classNames, styles, event handlers, and refs onto a single child element.
 *
 * Based on shadcn/ui Slot pattern (MIT licensed), simplified for our use cases:
 * - Conditional component pattern: `const Comp = asChild ? Slot : "button"`
 * - Early-return pattern: `if (asChild) return <Slot>{children}</Slot>`
 *
 * @packageDocumentation
 * @registryPartOf primitives
 */

import * as React from "react";

type AnyProps = Record<string, unknown>;

type AnyFn = (...args: unknown[]) => unknown;

function mergeRefs<T>(
  ...refs: Array<React.Ref<T> | undefined>
): React.RefCallback<T> {
  return (value) => {
    refs.forEach((ref) => {
      if (typeof ref === "function") {
        ref(value);
      } else if (ref != null) {
        (ref as React.MutableRefObject<T | null>).current = value;
      }
    });
  };
}

function mergeProps(slotProps: AnyProps, childProps: AnyProps): AnyProps {
  const result: AnyProps = { ...slotProps };

  for (const key in childProps) {
    const slotValue = slotProps[key];
    const childValue = childProps[key];

    const isHandler = /^on[A-Z]/.test(key);

    if (isHandler) {
      if (slotValue && childValue) {
        result[key] = (...args: unknown[]) => {
          (childValue as AnyFn)(...args);
          (slotValue as AnyFn)(...args);
        };
      } else {
        result[key] = childValue || slotValue;
      }
    } else if (key === "style") {
      result[key] = { ...(slotValue as object), ...(childValue as object) };
    } else if (key === "className") {
      result[key] = [slotValue, childValue].filter(Boolean).join(" ");
    } else {
      result[key] = childValue !== undefined ? childValue : slotValue;
    }
  }

  return result;
}

interface SlotProps extends React.HTMLAttributes<HTMLElement> {
  children?: React.ReactNode;
}

const Slot = React.forwardRef<HTMLElement, SlotProps>((props, forwardedRef) => {
  const { children, ...slotProps } = props;

  if (!React.isValidElement(children)) {
    if (
      process.env.NODE_ENV !== "production" &&
      children !== null &&
      children !== undefined
    ) {
      console.warn("Slot: Expected a single React element child");
    }
    return null;
  }

  const childElement = children as React.ReactElement<
    AnyProps & { ref?: React.Ref<unknown> }
  >;
  const mergedProps = mergeProps(slotProps, childElement.props);

  const childRef = (childElement as { ref?: React.Ref<unknown> }).ref;

  return React.cloneElement(childElement, {
    ...mergedProps,
    ref: forwardedRef
      ? mergeRefs(forwardedRef, childRef as React.Ref<HTMLElement>)
      : (childRef as React.Ref<HTMLElement>),
  });
});

Slot.displayName = "Slot";

export { Slot, mergeRefs, mergeProps };
export type { SlotProps };
